queries.sparql:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?instrument_type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:instrument_id ?cg . ?child a :Instrument ; p:id ?cg . ?l p:orchestra_id ?pg . ?parent a :Orchestras ; p:id ?pg . } GROUP BY ?child }
  ?child p:instrument_type ?instrument_type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Orchestras } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?orchestra_name ?instrument_type WHERE {
  ?orchestras_instruments a :Orchestras_Instruments .
  ?instruments a :Instrument .
  ?orchestras_instruments p:hasInstruments ?instruments .
  ?orchestras a :Orchestras .
  ?orchestras_instruments p:hasOrchestras ?orchestras .
  ?orchestras p:orchestra_name ?orchestra_name .
  ?instruments p:instrument_type ?instrument_type .
} }
  collective: { SELECT ?instrument_type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:instrument_id ?cg . ?child a :Instrument ; p:id ?cg . ?l p:orchestra_id ?pg . ?parent a :Orchestras ; p:id ?pg . } GROUP BY ?child }
  ?child p:instrument_type ?instrument_type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Orchestras } }
  FILTER(?nf = ?total)
} }
}
